interface UserRepository extends org.springframework.data.jpa.repository.JpaRepository<User, Long> {
    @org.springframework.data.jpa.repository.Modifying(clearAutomatically = true, flushAutomatically = true)
    @org.springframework.data.jpa.repository.Query("update User u set u.status = :status where u.lastLogin < :threshold")
    int bulkUpdateStatus(
        @org.springframework.data.repository.query.Param("status") String status,
        @org.springframework.data.repository.query.Param("threshold") java.time.Instant threshold
    );
}

class UserService {
    private final UserRepository repo;

    UserService(UserRepository repo) { this.repo = repo; }

    @org.springframework.transaction.annotation.Transactional
    public int deactivateOldUsers(java.time.Instant threshold) {
        return repo.bulkUpdateStatus("PASSIVE", threshold);
    }
}

